// app/page.tsx
import { revalidateTag } from 'next/cache';
import { getAllProducts } from '@/lib/db';

async function syncLatestCatalog() {
  'use server';

  revalidateTag('products', 'max');
}

export default async function Page() {
  const products = await getAllProducts();

  return (
    <main style={{ padding: 24, fontFamily: 'Arial, sans-serif' }}>
      <header style={{ display: 'flex', justifyContent: 'space-between', gap: 16, alignItems: 'center', marginBottom: 24 }}>
        <div>
          <h1 style={{ margin: '0 0 8px', fontSize: 32 }}>Product Catalog</h1>
          <p style={{ margin: 0, color: '#555' }}>
            Fast browsing with cached catalog data and background refresh on demand.
          </p>
        </div>

        <form action={syncLatestCatalog}>
          <button
            type="submit"
            style={{
              border: 'none',
              borderRadius: 8,
              background: '#111827',
              color: 'white',
              padding: '12px 16px',
              fontSize: 14,
              cursor: 'pointer'
            }}
          >
            Sync latest catalog
          </button>
        </form>
      </header>

      <section>
        <div style={{ marginBottom: 12, color: '#6b7280' }}>{products.length} products</div>
        <div style={{ display: 'grid', gap: 12 }}>
          {products.map((product) => (
            <article
              key={product.id}
              style={{
                border: '1px solid #e5e7eb',
                borderRadius: 12,
                padding: 16,
                background: 'white'
              }}
            >
              <h2 style={{ margin: '0 0 8px', fontSize: 20 }}>{product.name}</h2>
              <p style={{ margin: 0, color: '#374151' }}>${product.price}</p>
            </article>
          ))}
        </div>
      </section>
    </main>
  );
}


